const source = $('Webhook OS pronta').first().json;
const config = $input.first().json;
const body = source.body ?? {};
const headers = source.headers ?? {};
const configuredToken = String(config.ordem_pronta_webhook_token ?? '').trim();
const incomingToken = headers['x-webhook-token'] ?? headers['X-Webhook-Token'] ?? '';

if (configuredToken && incomingToken !== configuredToken) {
  throw new Error('Webhook token invalido.');
}

const telefone = String(body.clienteTelefoneNumerico ?? body.clienteTelefone ?? '').replace(/\D/g, '');
if (!telefone) {
  throw new Error('Telefone do cliente ausente no payload.');
}

const evolutionApiBaseUrl = String(config.evolution_api_base_url ?? '').trim();
const evolutionApiKey = String(config.evolution_api_key ?? '').trim();
const evolutionInstanceName = String(config.evolution_instance_name ?? '').trim();
if (!evolutionApiBaseUrl || !evolutionApiKey || !evolutionInstanceName) {
  throw new Error('Configuracoes da Evolution API incompletas no banco.');
}

const tipoEntrega = body.tipoEntrega === 'entrega' ? 'entrega' : 'retirada_loja';
const mensagem = body.mensagem || (tipoEntrega === 'entrega'
  ? 'seu conserto esta finalizado, nosso entregador ira realizar a entrega nas proximas horas'
  : 'vc ja pode retirar na loja');

return [{
  json: {
    ordemId: body.ordemId,
    clienteNome: body.clienteNome,
    telefone,
    tipoEntrega,
    mensagem,
    aparelhoMarca: body.aparelhoMarca,
    aparelhoModelo: body.aparelhoModelo,
    evolutionApiBaseUrl,
    evolutionApiKey,
    evolutionInstanceName,
  },
}];
